void permute(int[] nums, int start, List<List<Integer>> res) {
    if (start == nums.length) { res.add(toList(nums)); return; }
    for (int i = start; i < nums.length; i++) {
        swap(nums, start, i);
        permute(nums, start+1, res);
        swap(nums, start, i); // backtrack
    }
}

